INSERT INTO hvac_config_points (
	id,
	config,
	id_gateway
) VALUES

	(
		#{item.id},
		#{item.config},
		#{item.id_gateway}
	)

INSERT INTO hvac_field_data ( id, id_gateway, value, ts ) SELECT t1.id, t1.id_gateway, t1.value, t1.ts FROM ( VALUES
ROW ( #{item.id}, #{item.id_gateway}, #{item.value}, #{item.ts} )
) t1 (id, id_gateway, value, ts) JOIN ( SELECT id, id_gateway, MAX(ts) AS ts FROM hvac_field_data WHERE #{item.id} GROUP BY id ) t2 ON t2.id = t1.id AND TIMESTAMPDIFF(MINUTE, t2.ts, t1.ts) >= 5
